// ═══════════════════════════════════════════════════════════════
// TEMPLATE SANITIZADO — db_crear_huesped v1.1
// ═══════════════════════════════════════════════════════════════
// Este JSON es un template genérico para importar en n8n.
// No contiene credenciales, IDs de Sheet ni IDs de workflow reales.
//
// Antes de importar, reemplazar:
//   __SHEETS_ID__       → ID del Google Sheet del entorno
//   __ENTORNO__         → Nombre del entorno (ej: VITA_DELTA_PROD)
//   __CREDENTIAL_ID__   → ID de la credencial OAuth en n8n
//   __CREDENTIAL_NAME__ → Nombre de la credencial OAuth en n8n
//
// El mismo template sirve para DEV, TEST y PROD.
// Solo cambia __SHEETS_ID__ y las credenciales.
//
// TRIGGERS:
//   1. Manual Trigger — para pruebas desde n8n (usar pin data).
//   2. When Executed by Another Workflow — llamado desde db_crear_prereserva.
// Si el input viene vacío, devuelve input_invalido.
//
// DEDUPLICACIÓN:
//   Paso 1: busca por teléfono normalizado.
//   Paso 2: si no encuentra, busca por email normalizado.
//   Si encuentra por email y teléfono existente vacío → lo completa.
//
// NO TOCA: PRE_RESERVAS, RESERVAS, PAGOS, DISPONIBILIDAD_CACHE.
// NO actualiza primera_reserva_fecha ni total_reservas.
// ═══════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════
// NODO 1 — Resolver Input
// ═══════════════════════════════════════════════════════════════
// ALCANCE v1:
// ✅ Crea o actualiza un huésped en HUÉSPEDES.
// ✅ Deduplicación por teléfono primero, email como fallback.
// ✅ Normaliza teléfono y email antes de buscar.
// ✅ En modo actualizado, solo pisa campos con valor real.
// ✅ Escribe LOG_CAMBIOS en casos exitosos y en input_invalido.
//
// ❌ FUERA DE ALCANCE en v1:
//    - No toca PRE_RESERVAS, RESERVAS, PAGOS, DISPONIBILIDAD_CACHE
//    - No actualiza primera_reserva_fecha ni total_reservas
//      (responsabilidad de db_confirmar_reserva)
//    - No envía WhatsApp ni notificaciones
//    - No usa IA
//
// ⚠️  SHEETS_ID — __ENTORNO__
// Valor actual: __SHEETS_ID__
//
// ⚠️  TRIGGERS
// - Manual Trigger: para pruebas desde n8n. Pasar input via pin data.
// - When Executed by Another Workflow: llamado desde db_crear_prereserva.
// Si el input viene vacío, devuelve input_invalido — no hay MANUAL_INPUT.
//
// ⚠️  id_huesped usa max + 1. Max Concurrency = 1.
// ═══════════════════════════════════════════════════════════════

const SHEETS_ID = '__SHEETS_ID__'; // __ENTORNO__

const CANALES_VALIDOS = ['whatsapp', 'instagram', 'web', 'manual'];

function normalizarTelefono(tel) {
  if (!tel) return '';
  let t = String(tel).trim();
  // Quitar espacios, guiones, paréntesis, puntos
  t = t.replace(/[\s\-().]/g, '');
  // 0054... → +54...
  if (t.startsWith('00')) t = '+' + t.slice(2);
  // 54... (sin +) → +54...
  if (/^54\d/.test(t)) t = '+' + t;
  return t;
}

function normalizarEmail(email) {
  if (!email) return '';
  return String(email).trim().toLowerCase();
}

function valorReal(v) {
  if (v === null || v === undefined) return false;
  if (typeof v === 'string') return v.trim() !== '';
  return true;
}

const raw = $input.first()?.json ?? {};

const nombre          = String(raw.nombre        ?? '').trim();
const apellido        = String(raw.apellido       ?? '').trim();
const dni             = String(raw.dni            ?? '').trim();
const telefono        = normalizarTelefono(raw.telefono);
const email           = normalizarEmail(raw.email);
const canal_raw       = String(raw.canal_preferido ?? '').trim();
const canal_preferido = CANALES_VALIDOS.includes(canal_raw) ? canal_raw : 'whatsapp';
const notas_internas  = String(raw.notas_internas ?? '').trim();
const source_event    = String(raw.source_event   ?? 'manual').trim();

// ── Validaciones ─────────────────────────────────────────────
const errores = [];
if (!nombre)   errores.push('nombre es obligatorio');
if (!telefono) errores.push('telefono es obligatorio');

if (errores.length > 0) {
  return [{ json: {
    ok:        false,
    error:     'input_invalido',
    detalle:   errores,
    _validado: false,
    _log_warning: {
      tabla_afectada:   'HUÉSPEDES',
      id_registro:      'N/A',
      campo_modificado: 'validacion_input',
      valor_anterior:   '',
      valor_nuevo:      '',
      modificado_por:   'n8n',
      source_event,
      nivel:            'warning',
      detalle:          JSON.stringify({ error: 'input_invalido', detalle: errores })
    }
  }}];
}

return [{ json: {
  SHEETS_ID,
  nombre,
  apellido,
  dni,
  telefono,
  email,
  canal_preferido,
  notas_internas,
  source_event,
  ts_inicio: new Date().toISOString(),
  _validado: true
}}];

const d = $input.first().json;
return [{ json: {
  _output: { ok: d.ok, error: d.error, detalle: d.detalle },
  _log:    d._log_warning
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 2 — Buscar Huésped Existente
// ═══════════════════════════════════════════════════════════════
// Paso 1: buscar por teléfono normalizado.
// Paso 2: si no encuentra y hay email, buscar por email normalizado.
// Si encontró por email y el teléfono existente está vacío → completarlo.
// Si no encuentra nada → modo CREATE.
// ═══════════════════════════════════════════════════════════════

const inputData = $('Resolver Input').first().json;

function normTel(tel) {
  if (!tel) return '';
  let t = String(tel).trim().replace(/[\s\-().]/g, '');
  if (t.startsWith('00')) t = '+' + t.slice(2);
  if (/^54\d/.test(t)) t = '+' + t;
  return t;
}
function normEmail(e) {
  if (!e) return '';
  return String(e).trim().toLowerCase();
}
function valorReal(v) {
  if (v === null || v === undefined) return false;
  if (typeof v === 'string') return v.trim() !== '';
  return true;
}

const huespedes = ($('Agg HUÉSPEDES').first()?.json?.data ?? [])
  .filter(h => h && Object.keys(h).some(k => String(h[k]).trim() !== ''));

const ids = huespedes
  .map(h => parseInt(String(h.id_huesped ?? ''), 10))
  .filter(n => !isNaN(n) && n > 0);
const nuevo_id_huesped = (ids.length > 0 ? Math.max(...ids) : 0) + 1;

// Paso 1 — por teléfono
let huesped_existente = null;
let encontrado_por    = null;

if (inputData.telefono) {
  huesped_existente = huespedes.find(h => normTel(h.telefono) === inputData.telefono);
  if (huesped_existente) encontrado_por = 'telefono';
}

// Paso 2 — por email
if (!huesped_existente && inputData.email) {
  huesped_existente = huespedes.find(h => normEmail(h.email) === inputData.email);
  if (huesped_existente) encontrado_por = 'email';
}

const ahora = new Date().toISOString();

if (!huesped_existente) {
  return [{ json: {
    _modo:             'creado',
    _nuevo_id_huesped: nuevo_id_huesped,
    _huesped_existente: null,
    _encontrado_por:   null,
    _inputData:        inputData
  }}];
}

// Construir campos a actualizar — solo los que tienen valor real
const campos_update = {};
if (valorReal(inputData.nombre))          campos_update.nombre          = inputData.nombre;
if (valorReal(inputData.apellido))        campos_update.apellido        = inputData.apellido;
if (valorReal(inputData.dni))             campos_update.dni             = inputData.dni;
if (valorReal(inputData.email))           campos_update.email           = inputData.email;
if (valorReal(inputData.canal_preferido)) campos_update.canal_preferido = inputData.canal_preferido;
if (valorReal(inputData.notas_internas))  campos_update.notas_internas  = inputData.notas_internas;

// Si encontró por email y el teléfono existente está vacío → completarlo
if (encontrado_por === 'email' && !normTel(huesped_existente.telefono) && valorReal(inputData.telefono)) {
  campos_update.telefono = inputData.telefono;
}
campos_update.updated_at = ahora;

return [{ json: {
  _modo:              'actualizado',
  _id_huesped_actual: parseInt(String(huesped_existente.id_huesped), 10),
  _huesped_existente: huesped_existente,
  _encontrado_por:    encontrado_por,
  _campos_update:     campos_update,
  _inputData:         inputData
}}];

const d   = $input.first().json;
const ahora = new Date().toISOString();
return [{ json: {
  // Columnas reales de HUÉSPEDES para el update explícito
  id_huesped:      d._id_huesped_actual,
  nombre:          d._campos_update.nombre          ?? d._huesped_existente.nombre          ?? '',
  apellido:        d._campos_update.apellido        ?? d._huesped_existente.apellido        ?? '',
  dni:             d._campos_update.dni             ?? d._huesped_existente.dni             ?? '',
  telefono:        d._campos_update.telefono        ?? d._huesped_existente.telefono        ?? '',
  email:           d._campos_update.email           ?? d._huesped_existente.email           ?? '',
  canal_preferido: d._campos_update.canal_preferido ?? d._huesped_existente.canal_preferido ?? '',
  notas_internas:  d._campos_update.notas_internas  ?? d._huesped_existente.notas_internas  ?? '',
  updated_at:      d._campos_update.updated_at ?? ahora,
  // metadata interna (no se escribe en Sheets — se usan en LOG)
  _id_huesped:     d._id_huesped_actual,
  _modo:           'actualizado',
  _encontrado_por: d._encontrado_por,
  _inputData:      d._inputData
}}];

// Resumen para rama UPDATE
const d = $('Preparar LOG UPDATE').first().json;
return [{ json: {
  ok:             true,
  modo:           d._modo,
  id_huesped:     d._id_huesped,
  nombre:         d._inputData?.nombre,
  apellido:       d._inputData?.apellido   ?? '',
  telefono:       d._inputData?.telefono,
  email:          d._inputData?.email      ?? '',
  encontrado_por: d._encontrado_por,
  source_event:   d._inputData?.source_event
}}];

// Resumen para rama CREATE
const d = $('Preparar LOG CREATE').first().json;
return [{ json: {
  ok:             true,
  modo:           d._modo,
  id_huesped:     d._id_huesped,
  nombre:         d._inputData?.nombre,
  apellido:       d._inputData?.apellido   ?? '',
  telefono:       d._inputData?.telefono,
  email:          d._inputData?.email      ?? '',
  encontrado_por: null,
  source_event:   d._inputData?.source_event
}}];
